3	import { runStorageMigration, type StorageDatabase } from './migrations.js';
4	
5	/**
6	 * @ax/storage-postgres — postgres-backed peer of @ax/storage-sqlite.
7	 *
8	 * Same hook contract; different backend. Uses the shared Kysely instance
9	 * owned by @ax/database-postgres via `database:get-instance`. Per
10	 * Invariant 2, this plugin does NOT direct-import @ax/database-postgres
11	 * at runtime — the bus is the only inter-plugin API.
12	 */
13	
14	const PLUGIN_NAME = '@ax/storage-postgres';
15	
16	export function createStoragePostgresPlugin(): Plugin {
17	  let db: Kysely<StorageDatabase> | undefined;
18	
19	  return {
20	    manifest: {
21	      name: PLUGIN_NAME,
22	      version: '0.0.0',
23	      registers: ['storage:get', 'storage:set'],
24	      calls: ['database:get-instance'],
25	      subscribes: [],
26	    },
27	    async init({ bus }) {
28	      // bootstrap()'s topological order ensures database-postgres has
29	      // already registered `database:get-instance` before we run.
30	      // No caller AgentContext at init-time — synthesize one with
31	      // makeAgentContext(). The init context is purely for log correlation;
32	      // the underlying handler ignores it.
33	      const initCtx = makeAgentContext({
34	        sessionId: 'init',
35	        agentId: PLUGIN_NAME,
36	        userId: 'system',
37	      });
38	      // The bus contract is `Kysely<unknown>`; we cast at the edge to our
39	      // own typed schema. The shared instance ITSELF is just a Kysely
40	      // wrapped around a pg.Pool — the type parameter is purely a
41	      // compile-time witness for which tables exist, and our
42	      // table-prefix namespace (`storage_postgres_v1_*`) is owned by us.
43	      const { db: shared } = await bus.call<unknown, { db: Kysely<unknown> }>(
44	        'database:get-instance',
45	        initCtx,
46	        {},
47	      );
48	      db = shared as Kysely<StorageDatabase>;
49	      await runStorageMigration(db);
50	
51	      bus.registerService<{ key: string }, { value: Uint8Array | undefined }>(
52	        'storage:get',
53	        PLUGIN_NAME,
54	        async (_ctx, { key }) => {
55	          const row = await db!
56	            .selectFrom('storage_postgres_v1_kv')
57	            .select('value')
58	            .where('key', '=', key)
59	            .executeTakeFirst();
60	          if (row === undefined) return { value: undefined };
61	          // pg returns BYTEA as Buffer; expose as Uint8Array at the edge.
62	          return { value: new Uint8Array(row.value) };
63	        },
64	      );
65	
66	      bus.registerService<{ key: string; value: Uint8Array }, void>(
67	        'storage:set',
68	        PLUGIN_NAME,
69	        async (_ctx, { key, value }) => {
70	          // Buffer.from(Uint8Array) shares the underlying memory, so this
71	          // doesn't copy. Kysely's pg dialect serializes Buffer → BYTEA.
72	          const buf = Buffer.from(value);
73	          await db!
74	            .insertInto('storage_postgres_v1_kv')
75	            .values({ key, value: buf, updated_at: new Date() })
76	            .onConflict((oc) =>
77	              oc.column('key').doUpdateSet({
78	                value: buf,
79	                updated_at: new Date(),
80	              }),
81	            )
82	            .execute();
83	        },
84	      );
85	    },
86	  };
87	}
