1	#!/usr/bin/env node
2	import { createRequire } from 'node:module';
3	import { pathToFileURL } from 'node:url';
4	import {
5	  HookBus,
6	  bootstrap,
7	  makeAgentContext,
8	  type AgentOutcome,
9	  type Plugin,
10	} from '@ax/core';
11	import { llmMockPlugin } from '@ax/llm-mock';
12	import { createLlmAnthropicPlugin } from '@ax/llm-anthropic';
13	import { createStorageSqlitePlugin } from '@ax/storage-sqlite';
14	import { createCredentialsPlugin } from '@ax/credentials';
15	import { auditLogPlugin } from '@ax/audit-log';
16	import { createSandboxSubprocessPlugin } from '@ax/sandbox-subprocess';
17	import { createSessionInmemoryPlugin } from '@ax/session-inmemory';
18	import { createIpcServerPlugin } from '@ax/ipc-server';
19	import { createLlmProxyAnthropicFormatPlugin } from '@ax/llm-proxy-anthropic-format';
20	import { createChatOrchestratorPlugin } from '@ax/chat-orchestrator';
21	import { createToolDispatcherPlugin } from '@ax/tool-dispatcher';
22	import { createToolBashPlugin } from '@ax/tool-bash';
23	import { createToolFileIoPlugin } from '@ax/tool-file-io';
24	import { createMcpClientPlugin } from '@ax/mcp-client';
25	import { createDevAgentsStubPlugin } from './dev-agents-stub.js';
26	import { AxConfigSchema, type AxConfig, type AxConfigInput } from './config/schema.js';
27	import { loadAxConfig } from './config/load.js';
28	import { runCredentialsCommand } from './commands/credentials.js';
29	import { runMcpCommand } from './commands/mcp.js';
30	import { runServeCommand } from './commands/serve.js';
31	import { runAdminCommand } from './commands/admin.js';
32	
33	// `@ax/cli` is the ONE package permitted to import sibling plugins directly
34	// (eslint.config.mjs no-restricted-imports allowlist); this is also the one
35	// spot where we pin down the runner binary location (I8).
36	//
37	// Lazy-resolve the agent-native-runner binary inside main() rather than at
38	// module load. Library-mode consumers (tests, embedders using configOverride)
39	// that never invoke agent:invoke shouldn't fail to import @ax/cli just because
40	// the runner's dist/ hasn't been built yet. `createRequire` from the CLI's
41	// own URL is robust against pnpm hoisting and works identically in dev + prod.
42	//
43	// We resolve the package's `.` export (which is `dist/main.js`) rather than
44	// a subpath specifier: the runner's `exports` field only exposes `.` and
45	// `./turn-loop`, so a direct `./dist/main.js` subpath is blocked by Node's
46	// exports-map enforcement.
47	const requireFromCli = createRequire(import.meta.url);
48	export function resolveRunnerBinary(runner: AxConfig['runner']): string {
49	  // Exhaustive so a future `runner` variant in schema.ts fails typecheck
50	  // here instead of silently falling through to the native runner.
51	  switch (runner) {
52	    case 'claude-sdk':
53	      return requireFromCli.resolve('@ax/agent-claude-sdk-runner');
54	    case 'native':
55	      return requireFromCli.resolve('@ax/agent-native-runner');
56	    default: {
57	      const _exhaustive: never = runner;
58	      throw new Error(`unknown runner: ${String(_exhaustive)}`);
59	    }
60	  }
61	}
62	const DEFAULT_CHAT_TIMEOUT_MS = 10 * 60_000;
63	
64	export interface MainOptions {
65	  message: string;
66	  /**
67	   * Library-mode config override. When set, we skip file discovery entirely
68	   * — the override is parsed (to apply defaults) and used as-is. This is the
69	   * seam tests and embedders use to avoid touching disk.
70	   */
71	  configOverride?: AxConfigInput;
72	  /** Directory to walk for `ax.config.*`. Defaults to `process.cwd()`. */
73	  cwd?: string;
74	  /**
75	   * Override the sqlite DB path from config. Exists to keep legacy `AX_DB`
76	   * env-var binary-mode working while we phase config-driven storage in.
77	   */
78	  sqlitePath?: string;
79	  /**
80	   * Override `AgentContext.workspace.rootPath`. Defaults to `cwd`, which in
81	   * turn defaults to `process.cwd()`. Tool sandboxes land inside this dir.
82	   */
83	  workspaceRoot?: string;
84	  stdout?: (line: string) => void;
85	  stderr?: (line: string) => void;
86	  /**
87	   * Test-seam ONLY. When set and `cfg.llm === 'anthropic'`, replaces the real
88	   * SDK client with the factory result — same hatch the llm-anthropic plugin
89	   * already exposes, threaded through here for library-mode tests. Lives on
90	   * `MainOptions` (not in the JSON config schema) because functions aren't
91	   * JSON-serializable and this seam must not be reachable from file-based
92	   * config. Not used in binary-mode.
93	   */
94	  anthropicClientFactory?: (apiKey: string) => {
95	    messages: { create(req: Record<string, unknown>): Promise<unknown> };
96	  };
97	  /**
98	   * Test-seam ONLY. Extra plugins appended AFTER the config-driven plugin
99	   * set, before bootstrap. Lets library-mode tests inject observer plugins
100	   * (e.g. a `tool:post-call` subscriber that records events) and stub
101	   * service registrations (see `skipDefaultLlm`). Not reachable from
102	   * file-based config — plugins aren't JSON-serializable.
103	   */
104	  extraPlugins?: Plugin[];
105	  /**
106	   * Test-seam ONLY. When true, the default LLM plugin selected by
107	   * `cfg.llm` is NOT pushed — callers must supply an `llm:call` registrar
108	   * through `extraPlugins`. Exists because the hook bus enforces exactly
109	   * one registrar per service hook, so "override the default" means "don't
110	   * register the default". Not reachable from file-based config.
111	   */
112	  skipDefaultLlm?: boolean;
113	}
114	
115	const DEFAULT_SQLITE_PATH = './ax-next-chat.sqlite';
116	
117	export async function main(opts: MainOptions): Promise<number> {
118	  const out = opts.stdout ?? ((line) => process.stdout.write(line + '\n'));
119	  const err = opts.stderr ?? ((line) => process.stderr.write(line + '\n'));
120	
121	  const cwd = opts.cwd ?? process.cwd();
122	  const cfg: AxConfig =
123	    opts.configOverride !== undefined
124	      ? AxConfigSchema.parse(opts.configOverride)
125	      : await loadAxConfig({ cwd });
126	
127	  const bus = new HookBus();
128	
129	  const plugins: Plugin[] = [];
130	
131	  // Storage (always sqlite for now; schema gates this).
132	  plugins.push(
133	    createStorageSqlitePlugin({
134	      databasePath: opts.sqlitePath ?? DEFAULT_SQLITE_PATH,
135	    }),
136	  );
137	
138	  // Credentials sits immediately after storage (it calls storage:get/set) and
139	  // before any plugin that resolves `credential_ref`s via credentials:get
140	  // (e.g. @ax/mcp-client lands in Task 16). Bootstrap is topologically
141	  // ordered by declared calls/registers, but pushing in-order keeps the
142	  // intent obvious to readers. Init requires AX_CREDENTIALS_KEY in env.
143	  plugins.push(createCredentialsPlugin());
144	
145	  // Audit log is part of the canary loop.
146	  plugins.push(auditLogPlugin());
147	
148	  // Sandbox. Config only admits 'subprocess' today; the switch is future-
149	  // proofing for when alternate sandbox providers land.
150	  if (cfg.sandbox === 'subprocess') {
151	    plugins.push(createSandboxSubprocessPlugin());
152	  }
153	
154	  // Session + IPC + chat orchestration. Together these replace the old
155	  // in-process `registerChatLoop` — `agent:invoke` is now registered by
156	  // @ax/chat-orchestrator, which drives the per-chat lifecycle through
157	  // sandbox:open-session + session:queue-work and awaits chat:end from
158	  // the runner (delivered by @ax/ipc-server).
159	  plugins.push(createSessionInmemoryPlugin());
160	  plugins.push(createIpcServerPlugin());
161	  plugins.push(createLlmProxyAnthropicFormatPlugin());
162	  plugins.push(
163	    createChatOrchestratorPlugin({
164	      runnerBinary: resolveRunnerBinary(cfg.runner),
165	      chatTimeoutMs: DEFAULT_CHAT_TIMEOUT_MS,
166	    }),
167	  );
168	
169	  // Week 9.5: chat-orchestrator hard-depends on `agents:resolve`. The CLI
170	  // is the single-tenant dev loop — there's no admin endpoint, no team
171	  // ACL, no postgres-backed agent rows. We register a permissive stub
172	  // that returns the same agent for every (agentId, userId) pair so the
173	  // orchestrator's resolve gate is satisfied without standing up the
174	  // multi-tenant preset. Production presets register the real @ax/agents
175	  // plugin instead; the kernel's "exactly one impl per service hook" rule
176	  // catches accidental dual-loading. See dev-agents-stub.ts.
177	  plugins.push(createDevAgentsStubPlugin());
178	
179	  // Tool dispatcher is the single entry point for `tool:execute`, fanning
180	  // out to whatever tool plugins register descriptors. Always present when
181	  // we might have tools. (After Task 7, bash/file-io here are descriptor-
182	  // only — actual execution runs in the sandbox via the impl packages.)
183	  plugins.push(createToolDispatcherPlugin());
184	  if (cfg.tools.includes('bash')) {
185	    plugins.push(createToolBashPlugin());
186	  }
187	  if (cfg.tools.includes('file-io')) {
188	    plugins.push(createToolFileIoPlugin());
189	  }
190	
191	  // MCP-sourced tools register through the same `tool:register` surface as
192	  // bash/file-io. Push unconditionally: when no MCP configs are stored,
193	  // `loadConfigs` returns an empty array and init is a no-op. Ordering
194	  // note: must come AFTER tool-dispatcher (which registers `tool:register`)
195	  // and AFTER credentials + storage-sqlite (which it calls during init).
196	  // Bootstrap's topological sort handles this either way, but keeping the
197	  // push order aligned with the call graph keeps readers grounded.
198	  plugins.push(createMcpClientPlugin());
199	
200	  // LLM selection. `exactOptionalPropertyTypes` on the Anthropic plugin
201	  // config means we can't just splat through fields whose type is
202	  // `string | undefined` — we strip undefined keys first.
203	  //
204	  // `skipDefaultLlm` is a test-only seam: callers that want to supply their
205	  // own `llm:call` registrar via `extraPlugins` set it so we don't emit a
206	  // default (duplicate-service would throw at bootstrap).
207	  if (opts.skipDefaultLlm !== true) {
208	    if (cfg.llm === 'anthropic') {
209	      const a = cfg.anthropic ?? {};
210	      const anthropicCfg: {
211	        model?: string;
212	        maxTokens?: number;
213	        clientFactory?: (apiKey: string) => {
214	          messages: { create(req: Record<string, unknown>): Promise<unknown> };
215	        };
216	      } = {};
217	      if (a.model !== undefined) anthropicCfg.model = a.model;
218	      if (a.maxTokens !== undefined) anthropicCfg.maxTokens = a.maxTokens;
219	      // `anthropicClientFactory` is MainOptions-only (not in AxConfig), so we
220	      // thread it through here for the library-mode e2e test seam.
221	      if (opts.anthropicClientFactory !== undefined) {
222	        anthropicCfg.clientFactory = opts.anthropicClientFactory;
223	      }
224	      plugins.push(createLlmAnthropicPlugin(anthropicCfg));
225	    } else {
226	      plugins.push(llmMockPlugin());
227	    }
228	  }
229	
230	  // Library-mode test-only: extra plugins appended last so they can add
231	  // subscribers that observe the full plugin set and (in combination with
232	  // `skipDefaultLlm`) supply an alternative `llm:call` registrar.
233	  if (opts.extraPlugins !== undefined) {
234	    plugins.push(...opts.extraPlugins);
235	  }
236	
237	  const handle = await bootstrap({ bus, plugins, config: {} });
238	
239	  const ctx = makeAgentContext({
240	    sessionId: 'cli-session',
241	    agentId: 'cli-agent',
242	    userId: 'cli-user',
243	    workspace: { rootPath: opts.workspaceRoot ?? cwd },
244	  });
245	
246	  try {
247	    const outcome: AgentOutcome = await bus.call('agent:invoke', ctx, {
248	      message: { role: 'user', content: opts.message },
249	    });
250	
251	    if (outcome.kind === 'complete') {
252	      const last = outcome.messages[outcome.messages.length - 1];
253	      out(last?.content ?? '');
254	      return 0;
255	    }
256	    err(`chat terminated: ${outcome.reason}`);
257	    return 1;
258	  } finally {
259	    await handle.shutdown();
260	  }
261	}
262	
263	if (process.argv[1] && import.meta.url === pathToFileURL(process.argv[1]).href) {
264	  const sqlitePath = process.env.AX_DB ?? DEFAULT_SQLITE_PATH;
265	  const argv = process.argv.slice(2);
266	
267	  // Subcommand dispatch. Intercept BEFORE the chat path so we don't bootstrap
268	  // the full LLM/sandbox/orchestrator plugin set for what's essentially a
269	  // "write a row to sqlite" operation — and so we don't race the chat path's
270	  // DB init.
271	  if (argv[0] === 'credentials') {
272	    runCredentialsCommand({
273	      argv: argv.slice(1),
274	      stdin: process.stdin,
275	      sqlitePath,
276	    })
277	      .then((code) => process.exit(code))
278	      .catch((e) => {
279	        // The command itself turns PluginError into stderr+exit-1. Anything
280	        // reaching here is truly unexpected — be boring so we don't echo
281	        // something we shouldn't.
282	        process.stderr.write(`fatal: ${e instanceof Error ? e.message : String(e)}\n`);
283	        process.exit(2);
284	      });
285	  } else if (argv[0] === 'mcp') {
286	    runMcpCommand({
287	      argv: argv.slice(1),
288	      stdin: process.stdin,
289	      sqlitePath,
290	    })
291	      .then((code) => process.exit(code))
292	      .catch((e) => {
293	        process.stderr.write(`fatal: ${e instanceof Error ? e.message : String(e)}\n`);
294	        process.exit(2);
295	      });
296	  } else if (argv[0] === 'admin') {
297	    // One-shot admin tooling. Today: `bootstrap` (first-admin against
298	    // /auth/dev-bootstrap). Like credentials/mcp this intercepts BEFORE
299	    // the chat path so we don't bootstrap the LLM/sandbox/orchestrator
300	    // plugin set for what's a thin HTTP client.
301	    runAdminCommand({ argv: argv.slice(1) })
302	      .then((code) => process.exit(code))
303	      .catch((e) => {
304	        process.stderr.write(`fatal: ${e instanceof Error ? e.message : String(e)}\n`);
305	        process.exit(2);
306	      });
307	  } else if (argv[0] === 'serve') {
308	    // Long-running k8s-mode entrypoint. The chart's host pod runs this.
309	    // Local-dev users running `node dist/cli/index.js serve` will boot the
310	    // full k8s preset — they need DATABASE_URL + AX_K8S_HOST_IPC_URL +
311	    // AX_WORKSPACE_BACKEND set, otherwise we exit 2 with a clear message.
312	    runServeCommand({ argv: argv.slice(1) })
313	      .then((code) => process.exit(code))
314	      .catch((e) => {
315	        process.stderr.write(`fatal: ${e instanceof Error ? e.message : String(e)}\n`);
316	        process.exit(2);
317	      });
318	  } else {
319	    const message = argv.join(' ') || 'hi';
320	    // Note: SIGINT/SIGTERM during agent:invoke is NOT gracefully handled here.
321	    // The CLI is one-shot — for a clean shutdown we'd need to thread cancel
322	    // signals into the agent:invoke hook, which is its own slice. The try/finally
323	    // around agent:invoke inside main() handles the normal completion path
324	    // (incl. errors that bubble up) for storage-sqlite WAL flush etc.
325	    main({ message, sqlitePath })
326	      .then((code) => process.exit(code))
327	      .catch((e) => {
328	        process.stderr.write(`fatal: ${e instanceof Error ? e.message : String(e)}\n`);
329	        process.exit(2);
330	      });
331	  }
332	}
