1	// ax-next credentials set <id>
2	//
3	// A stdin-only path for writing a secret. The secret value NEVER appears in
4	// argv — we read it from stdin so it doesn't leak to `ps` / `/proc/<pid>/cmdline`
5	// / shell history. We also don't echo it back on stdout or stderr; the only
6	// confirmation is the id. Paranoid? Sure. Also correct.
7	import { HookBus, bootstrap, makeAgentContext, PluginError } from '@ax/core';
8	import { createStorageSqlitePlugin } from '@ax/storage-sqlite';
9	import { createCredentialsPlugin } from '@ax/credentials';
10	
11	const DEFAULT_SQLITE_PATH = './ax-next-chat.sqlite';
12	
13	export interface RunCredentialsOptions {
14	  /** argv slice starting at the subcommand args, e.g. ['set', 'gh-token']. */
15	  argv: string[];
16	  /** The secret source. Reads all chunks to EOF, UTF-8 decodes, strips one trailing \n. */
17	  stdin: NodeJS.ReadableStream | AsyncIterable<Buffer | string>;
18	  stdout?: (line: string) => void;
19	  stderr?: (line: string) => void;
20	  /** Defaults to ./ax-next-chat.sqlite (same as main()). Tests override. */
21	  sqlitePath?: string;
22	}
23	
24	const USAGE = `usage: ax-next credentials set <id>
25	  <id> must match [a-z0-9][a-z0-9_.-]{0,127}
26	  the secret is read from stdin (NOT argv) — pipe or paste then EOF
27	
28	env:
29	  AX_CREDENTIALS_KEY  required, 32 bytes (64 hex chars or 44 base64 chars)`;
30	
31	export async function runCredentialsCommand(opts: RunCredentialsOptions): Promise<number> {
32	  const out = opts.stdout ?? ((line: string) => process.stdout.write(line + '\n'));
33	  const err = opts.stderr ?? ((line: string) => process.stderr.write(line + '\n'));
34	
35	  const verb = opts.argv[0];
36	  if (verb !== 'set') {
37	    err(USAGE);
38	    return 2;
39	  }
40	  const id = opts.argv[1];
41	  if (id === undefined || id === '') {
42	    err(USAGE);
43	    return 2;
44	  }
45	
46	  // Read stdin to a Buffer (preserves bytes), then UTF-8 decode.
47	  const chunks: Buffer[] = [];
48	  for await (const chunk of opts.stdin) {
49	    chunks.push(typeof chunk === 'string' ? Buffer.from(chunk, 'utf8') : Buffer.from(chunk));
50	  }
51	  let value = Buffer.concat(chunks).toString('utf8');
52	  // Strip exactly one trailing \n — covers `echo $TOKEN | ax-next ...` and a
53	  // single hand-typed newline before EOF. Don't trim aggressively: the user
54	  // might genuinely want trailing whitespace inside their token.
55	  if (value.endsWith('\n')) value = value.slice(0, -1);
56	
57	  const bus = new HookBus();
58	  let handle;
59	  try {
60	    handle = await bootstrap({
61	      bus,
62	      plugins: [
63	        createStorageSqlitePlugin({ databasePath: opts.sqlitePath ?? DEFAULT_SQLITE_PATH }),
64	        createCredentialsPlugin(),
65	      ],
66	      config: {},
67	    });
68	  } catch (e) {
69	    // bootstrap errors (e.g. credentials plugin init when AX_CREDENTIALS_KEY
70	    // is missing) come through here. No handle yet — nothing to shut down.
71	    if (e instanceof PluginError) {
72	      err(`error: ${e.message}`);
73	      return 1;
74	    }
75	    err('error: unexpected failure');
76	    return 1;
77	  }
78	
79	  try {
80	    try {
81	      await bus.call(
82	        'credentials:set',
83	        makeAgentContext({ sessionId: 'cli', agentId: 'cli', userId: 'cli' }),
84	        { id, value },
85	      );
86	    } catch (e) {
87	      if (e instanceof PluginError) {
88	        // PluginError messages are curated by @ax/credentials specifically to
