          for (const tool of listed.tools) {
            const desc = tool.description !== undefined && tool.description !== ''
              ? `  — ${tool.description}`
              : '';
            out(`  ${tool.name}${desc}`);
          }
          await connection.disconnect();
          return 0;
        });
      } catch (e) {
        if (e instanceof PluginError) {
          err(`error: ${e.message}`);
          return 1;
        }
        err(`error: ${e instanceof Error ? e.message : 'unexpected failure'}`);
