81	export function signCookieValue(key: Buffer, value: string): string {
82	  assertKeyLength(key);
83	  const payload = Buffer.from(value, 'utf8');
84	  if (payload.length > MAX_COOKIE_VALUE_BYTES) {
85	    throw new PluginError({
86	      code: 'invalid-payload',
87	      plugin: PLUGIN_NAME,
88	      message: `signed cookie value exceeds ${MAX_COOKIE_VALUE_BYTES}-byte cap`,
89	    });
