100	export function verifyCookieValue(key: Buffer, wire: string): string | null {
101	  assertKeyLength(key);
102	  if (typeof wire !== 'string' || wire.length === 0) return null;
103	  // Use lastIndexOf so any '.' inside a base64url payload (none, but
104	  // guard anyway) doesn't fool the split — but accept an empty payload
105	  // segment (dot at index 0) so empty-string values roundtrip.
106	  const dot = wire.lastIndexOf('.');
107	  if (dot < 0 || dot === wire.length - 1) return null;
108	  const payloadPart = wire.slice(0, dot);
109	  const sigPart = wire.slice(dot + 1);
